--[[ VARIABLES ]] local clicks = 0; local clickAmount = 1; local currentPrice = 15; local addedPrices = 20; local addedClicks = 5; local player = game.Players.LocalPlayer; --[[GUI]] local gui = Instance.new("ScreenGui", player:WaitForChild("PlayerGui")); --[[FRAME]] local frame = Instance.new("Frame", gui); frame.Size = UDim2.new(0.3, 0, 0.75, 0); frame.AnchorPoint = Vector2.new(0.5, 0.5); frame.BackgroundTransparency = 0.25; frame.BackgroundColor3 = Color3.new(0, 0, 0); frame.Position = UDim2.new(0.5, 0, 0.5, 0); Instance.new("UIDragDetector", frame); Instance.new("UICorner", frame).CornerRadius = UDim.new(0, 20) --[[BUTTON]] local button = Instance.new("ImageButton", frame); button.Size = UDim2.new(0.5, 0, 0.25, 0); button.Position = UDim2.new(0.5, 0, 0.3, 0); button.BackgroundTransparency = 0.5; button.Image = "rbxassetid://243443001"; button.AnchorPoint = Vector2.new(0.5, 0.5); button.BackgroundColor3 = Color3.new(0, 0, 0); Instance.new("UICorner", button).CornerRadius = UDim.new(1,0); Instance.new("UIAspectRatioConstraint", button); --[[LABEL]] local label = Instance.new("TextLabel", frame); label.BackgroundTransparency = 1; label.AnchorPoint = Vector2.new(0.5, 0.5); label.Position = UDim2.new(0.5, 0, 0.7, 0); label.Size = UDim2.new(0.5, 0, 0.2, 0); label.TextScaled = true; label.TextColor3 = Color3.new(1, 1, 1); label.Font = Enum.Font.Code; label.Text = tostring(clicks); --[[SOUND]] local sound = Instance.new("Sound", gui); sound.SoundId = "rbxassetid://139658322785649"; --[[BUY-BUTTON]] local buyButton = Instance.new("TextButton", frame); buyButton.Text = `Buy +{addedClicks} Click [{currentPrice} Clicks]`; buyButton.TextScaled = true; buyButton.AnchorPoint = Vector2.new(0.5, 0.5); buyButton.Size = UDim2.new(0.5, 0, 0.1, 0); buyButton.Position = UDim2.new(0.5, 0, 0.85); buyButton.BackgroundColor3 = Color3.fromRGB(26, 176, 0); buyButton.TextColor3 = Color3.new(1,1,1); Instance.new("UICorner", buyButton).CornerRadius = UDim.new(1,0) --[[##EVENTS##]] button.MouseButton1Click:Connect(function() sound:Play(); clicks = clicks + clickAmount; label.Text = tostring(clicks) end); button.MouseEnter:Connect(function() button:TweenSize(UDim2.new(0.6, 0, 0.6, 0), Enum.EasingDirection.Out, Enum.EasingStyle.Quad, 0.15) end); button.MouseLeave:Connect(function() button:TweenSize(UDim2.new(0.5, 0, 0.5, 0), Enum.EasingDirection.Out, Enum.EasingStyle.Quad, 0.15) end); buyButton.MouseButton1Click:Connect(function() if currentPrice <= clicks then clicks -= math.floor(currentPrice); currentPrice = math.floor(currentPrice * 1.6); clickAmount += addedClicks; addedClicks = math.floor(addedClicks * 1.2) + 2; buyButton.Text = `Buy +{addedClicks} Click [{currentPrice} Clicks]`; label.Text = tostring(clicks); else print(clicks) buyButton.Interactable = false; buyButton.Text = "Not enough clicks!"; task.wait(0.25); buyButton.Text = `Buy +{addedClicks} Click [{currentPrice} Clicks]`; buyButton.Interactable = true; end end)